const MAX_RELATED = 10;
const VALID_RELATIONSHIP_TYPES: ReadonlySet<string> = new Set(
  Object.values(NearbyPlaceRelationshipType),
);

function assertNearbyPlaceDiscoveryGraph(
  graph: Record<string, readonly RelatedPlace[]>,
): void {
  const placeSlugs = new Set(nearbyWeekendPlaces.map((p) => p.slug));
  const errors: string[] = [];
  for (const [slug, related] of Object.entries(graph)) {
    if (!placeSlugs.has(slug)) errors.push(`${slug}: source place not found in nearby-places.ts`);
    if (related.length > MAX_RELATED) errors.push(`${slug}: ${related.length} related places exceeds max ${MAX_RELATED}`);
    const seen = new Set<string>();
    for (const r of related) {
      if (r.placeSlug === slug) errors.push(`${slug}: self-reference`);
      if (seen.has(r.placeSlug)) errors.push(`${slug}: duplicate reference to ${r.placeSlug}`);
      seen.add(r.placeSlug);
      if (!placeSlugs.has(r.placeSlug)) errors.push(`${slug}: related place ${r.placeSlug} not found in nearby-places.ts`);
      if (!VALID_RELATIONSHIP_TYPES.has(r.relationshipType)) errors.push(`${slug}: invalid relationshipType ${r.relationshipType}`);
      if (typeof r.distanceKm !== "number" || r.distanceKm <= 0) errors.push(`${slug}: non-positive distanceKm for ${r.placeSlug}`);
    }
  }
  if (errors.length > 0) {
    throw new Error(`Invalid nearby-place discovery graph (${errors.length}):\n  - ${errors.join("\n  - ")}`);
  }
}

// Build-time gate: fails `next build` on any invalid edge.
assertNearbyPlaceDiscoveryGraph(NEARBY_PLACE_DISCOVERY_GRAPH);

export function getRelatedPlaces(placeSlug: string): readonly RelatedPlace[] {
  return NEARBY_PLACE_DISCOVERY_GRAPH[placeSlug] ?? [];
}

export function hasRelatedPlaces(placeSlug: string): boolean {
  return getRelatedPlaces(placeSlug).length > 0;
}

const RELATIONSHIP_LABEL: Record<NearbyPlaceRelationshipType, string> = {
  [NearbyPlaceRelationshipType.NearbyPlace]: "Nearby place",
  [NearbyPlaceRelationshipType.SameRegion]: "Same region",
  [NearbyPlaceRelationshipType.SameProtectedAreaSystem]: "Same protected-area system",
  [NearbyPlaceRelationshipType.SameMountainRegion]: "Same mountain region",
  [NearbyPlaceRelationshipType.SameCoastline]: "Same coastline",
  [NearbyPlaceRelationshipType.SameRiverSystem]: "Same river system",
  [NearbyPlaceRelationshipType.SameLakeRegion]: "Same lake region",
  [NearbyPlaceRelationshipType.SameEcoregion]: "Same ecoregion",
  [NearbyPlaceRelationshipType.WeekendAlternative]: "Weekend alternative",
  [NearbyPlaceRelationshipType.CrossBorderNature]: "Cross-border nature",
};

export function getNearbyPlaceRelationshipLabel(
  t: NearbyPlaceRelationshipType,
): string {
  return RELATIONSHIP_LABEL[t];
}
